const input = $input.first().json;
const THIRTY_DAYS_MS = 30 * 24 * 60 * 60 * 1000;

// Pure JS SHA-256 (no require needed)
function sha256(bytes) {
  const H0 = [0x6a09e667,0xbb67ae85,0x3c6ef372,0xa54ff53a,0x510e527f,0x9b05688c,0x1f83d9ab,0x5be0cd19];
  const K = [0x428a2f98,0x71374491,0xb5c0fbcf,0xe9b5dba5,0x3956c25b,0x59f111f1,0x923f82a4,0xab1c5ed5,0xd807aa98,0x12835b01,0x243185be,0x550c7dc3,0x72be5d74,0x80deb1fe,0x9bdc06a7,0xc19bf174,0xe49b69c1,0xefbe4786,0x0fc19dc6,0x240ca1cc,0x2de92c6f,0x4a7484aa,0x5cb0a9dc,0x76f988da,0x983e5152,0xa831c66d,0xb00327c8,0xbf597fc7,0xc6e00bf3,0xd5a79147,0x06ca6351,0x14292967,0x27b70a85,0x2e1b2138,0x4d2c6dfc,0x53380d13,0x650a7354,0x766a0abb,0x81c2c92e,0x92722c85,0xa2bfe8a1,0xa81a664b,0xc24b8b70,0xc76c51a3,0xd192e819,0xd6990624,0xf40e3585,0x106aa070,0x19a4c116,0x1e376c08,0x2748774c,0x34b0bcb5,0x391c0cb3,0x4ed8aa4a,0x5b9cca4f,0x682e6ff3,0x748f82ee,0x78a5636f,0x84c87814,0x8cc70208,0x90befffa,0xa4506ceb,0xbef9a3f7,0xc67178f2];
  const rotr = (x, n) => (x >>> n) | (x << (32 - n));
  const msg = Array.from(bytes);
  const msgLen = msg.length;
  msg.push(0x80);
  while (msg.length % 64 !== 56) msg.push(0);
  const bitLen = msgLen * 8;
  msg.push(0, 0, 0, 0, (bitLen >>> 24) & 0xff, (bitLen >>> 16) & 0xff, (bitLen >>> 8) & 0xff, bitLen & 0xff);
  const h = [...H0];
  for (let i = 0; i < msg.length; i += 64) {
    const w = new Array(64);
    for (let j = 0; j < 16; j++) w[j] = ((msg[i+j*4]<<24)|(msg[i+j*4+1]<<16)|(msg[i+j*4+2]<<8)|msg[i+j*4+3])>>>0;
    for (let j = 16; j < 64; j++) {
      const s0 = rotr(w[j-15],7)^rotr(w[j-15],18)^(w[j-15]>>>3);
      const s1 = rotr(w[j-2],17)^rotr(w[j-2],19)^(w[j-2]>>>10);
      w[j] = (w[j-16]+s0+w[j-7]+s1)>>>0;
    }
    let [a,b,c,d,e,f,g,hv] = h;
    for (let j = 0; j < 64; j++) {
      const S1 = rotr(e,6)^rotr(e,11)^rotr(e,25);
      const ch = (e&f)^(~e&g);
      const t1 = (hv+S1+ch+K[j]+w[j])>>>0;
      const S0 = rotr(a,2)^rotr(a,13)^rotr(a,22);
      const maj = (a&b)^(a&c)^(b&c);
      const t2 = (S0+maj)>>>0;
      hv=g; g=f; f=e; e=(d+t1)>>>0; d=c; c=b; b=a; a=(t1+t2)>>>0;
    }
    h[0]=(h[0]+a)>>>0; h[1]=(h[1]+b)>>>0; h[2]=(h[2]+c)>>>0; h[3]=(h[3]+d)>>>0;
    h[4]=(h[4]+e)>>>0; h[5]=(h[5]+f)>>>0; h[6]=(h[6]+g)>>>0; h[7]=(h[7]+hv)>>>0;
  }
  const result = [];
  for (const word of h) result.push((word>>>24)&0xff,(word>>>16)&0xff,(word>>>8)&0xff,word&0xff);
  return result;
}

function strToBytes(s) { return Array.from(s).map(c => c.charCodeAt(0)); }
function bytesToHex(bytes) { return bytes.map(b => b.toString(16).padStart(2,'0')).join(''); }

function hmacSha256(keyStr, msgStr) {
  let key = strToBytes(keyStr);
  if (key.length > 64) key = sha256(key);
  while (key.length < 64) key.push(0);
  const ipad = key.map(b => b ^ 0x36);
  const opad = key.map(b => b ^ 0x5c);
  const innerHash = sha256([...ipad, ...strToBytes(msgStr)]);
  return bytesToHex(sha256([...opad, ...innerHash]));
}

function timingSafeEqual(a, b) {
  if (a.length !== b.length) return false;
  let result = 0;
  for (let i = 0; i < a.length; i++) result |= a.charCodeAt(i) ^ b.charCodeAt(i);
  return result === 0;
}

if (input.action === 'sign') {
  const expiry = Date.now() + THIRTY_DAYS_MS;
  const payload = `${input.client_slug}:${input.source_type}:${input.source_ref}:${expiry}`;
  const payload_b64 = Buffer.from(payload, 'utf8').toString('base64url');
  const token = hmacSha256(input.secret, payload);
  return [{ json: { token, payload_b64 } }];
}

if (input.action === 'verify') {
  let payload;
  try {
    payload = Buffer.from(input.payload_b64, 'base64url').toString('utf8');
  } catch (e) {
    return [{ json: { valid: false, reason: 'malformed_payload' } }];
  }
  const parts = payload.split(':');
  if (parts.length !== 4) return [{ json: { valid: false, reason: 'malformed_payload' } }];
  const [client_slug, source_type, source_ref, expiryStr] = parts;
  const expiry = Number(expiryStr);
  const expectedToken = hmacSha256(input.secret, payload);
  if (!timingSafeEqual(input.token || '', expectedToken)) return [{ json: { valid: false, reason: 'signature_mismatch' } }];
  if (Number.isNaN(expiry) || Date.now() > expiry) return [{ json: { valid: false, reason: 'expired' } }];
  return [{ json: { valid: true, client_slug, source_type, source_ref } }];
}

return [{ json: { valid: false, reason: 'unknown_action' } }];
